var timestamps = msg.map(singleMeasure => singleMeasure.ts); // get the timestamps

/* calculate maximum and minimum and save
it into metadata */
metadata.maxTimestamp = Math.max(...timestamps);
metadata.minTimestamp = Math.min(...timestamps);

/* use this script to remove also the 
prefix "ss_" to the server attributes 
got by the asset */
for(const metadataKey of metadata){
    if(metadataKey.startsWith("ss_")){
        var newKey = metadataKey.replace("ss_", ""); // create a new key removing the prefix
        metadata[newKey] = metadata[metadataKey]; // move the content to the new key
        delete metadata[metadataKey]; // delete the previous key
    }
}

return {msg: msg, metadata: metadata, msgType: msgType};

