configuration.jsScript:
var currentIndex, currentKey,
    telemetryList; // variable declaration
var removeIndexes = []; // list of index to be removed
/* check for each telemetry if it's closer 
to the average */
for (var i = 0; i < msg.length; i++) {
    const singleMessage = msg[i];
    /* initialising the variables at the beginning
    of each cycle */
    currentIndex = -1;
    currentKey = Object.keys(singleMessage.values)[0];
    /* find if there's the telemetry inside the list 
    if there's a list of telemetries */
    if (currentKey in metadata) {
        telemetryList = JSON.parse(metadata[currentKey]);
        currentIndex = telemetryList.findIndex(
            singleTelemetry => singleTelemetry.ts ===
            singleMessage.ts);
    }

    /* if there is no telemetry with that timestamp
    just continue */
    if (currentIndex < 0)
        continue;

    /* otherwise control if you have the average
    and see if the new value is closer to average, 
    otherwise remove it */
    if ('general_' + currentKey in metadata && Math.abs(
            metadata['general_' + currentKey] -
            singleMessage.values[currentKey]) >= Math.abs(
            metadata['general_' + currentKey] - telemetryList[currentIndex].value))
        removeIndexes.push(i);
}

/* pass the message and remove 
all the telemetries that are in the index */
var message = msg.filter((singleMeasure, index) => !
    removeIndexes.includes(index));

return {
    msg: message,
    metadata: metadata,
    msgType: msgType
};
